const purchase = $('02. Chercher config').first().json;
const logs = $('03. Historique modifications').all().map(i => i.json);

return [{ json: {
  success: true,
  data: {
    purchaseId: purchase.id,
    automationNom: purchase.nom,
    automationCode: purchase.code,
    categorie: purchase.categorie,
    complexity: purchase.complexity,
    status: purchase.status,
    config: purchase.config || {},
    activatedAt: purchase.activated_at,
    updatedAt: purchase.updated_at,
    logs
  }
} }];
